  1→#!/bin/bash
  2→
  3→# TaskAI Server Migration Script
  4→# Migrates from SprintSpark naming to TaskAI naming on the server
  5→#
  6→# This script handles:
  7→# 1. DNS records (Cloudflare) - staging.taskai.cc, mcp.staging.taskai.cc
  8→# 2. Server directory renames
  9→# 3. DB file renames
 10→# 4. Webhook config update
 11→# 5. Nginx config for new domains
 12→# 6. SSL certificates
 13→# 7. GitHub secrets
 14→
 15→set -e
 16→
 17→# Colors
 18→RED='\033[0;31m'
 19→GREEN='\033[0;32m'
 20→YELLOW='\033[1;33m'
 21→BLUE='\033[0;34m'
 22→NC='\033[0m'
 23→
 24→# Server
 25→REMOTE_HOST="31.97.102.48"
 26→REMOTE_USER="ubuntu"
 27→SSH="ssh -o ConnectTimeout=10 ${REMOTE_USER}@${REMOTE_HOST}"
 28→
 29→# Cloudflare
 30→CF_ZONE_TASKAI="7850b043136ac339940ce64ff03ca878"
 31→SERVER_IP="31.97.102.48"
 32→
 33→# Domains
 34→STAGING_DOMAIN="staging.taskai.cc"
 35→STAGING_MCP_DOMAIN="mcp.staging.taskai.cc"
 36→
 37→info()  { echo -e "${BLUE}[INFO]${NC} $1"; }
 38→ok()    { echo -e "${GREEN}[OK]${NC} $1"; }
 39→warn()  { echo -e "${YELLOW}[WARN]${NC} $1"; }
 40→fail()  { echo -e "${RED}[FAIL]${NC} $1"; }
 41→step()  { echo -e "\n${BLUE}━━━ Step $1: $2 ━━━${NC}"; }
 42→
 43→# Check prerequisites
 44→check_prereqs() {
 45→    info "Checking prerequisites..."
 46→
 47→    if [ -z "$CLOUDFLARE_EMAIL" ] || [ -z "$CLOUDFLARE_API_KEY" ]; then
 48→        fail "Set CLOUDFLARE_EMAIL and CLOUDFLARE_API_KEY environment variables"
 49→        echo "  export CLOUDFLARE_EMAIL='your-email@example.com'"
 50→        echo "  export CLOUDFLARE_API_KEY='your-global-api-key'"
 51→        exit 1
 52→    fi
 53→
 54→    if ! command -v gh &>/dev/null; then
 55→        fail "GitHub CLI (gh) not found"
 56→        exit 1
 57→    fi
 58→
 59→    if ! $SSH "echo ok" &>/dev/null; then
 60→        fail "Cannot SSH to ${REMOTE_USER}@${REMOTE_HOST}"
 61→        exit 1
 62→    fi
 63→
 64→    ok "All prerequisites met"
 65→}
 66→
 67→# Step 1: Create DNS records
 68→create_dns() {
 69→    step 1 "Creating DNS records"
 70→
 71→    for RECORD_NAME in "$STAGING_DOMAIN" "$STAGING_MCP_DOMAIN"; do
 72→        info "Checking DNS for ${RECORD_NAME}..."
 73→
 74→        EXISTING=$(curl -s -X GET \
 75→            "https://api.cloudflare.com/client/v4/zones/${CF_ZONE_TASKAI}/dns_records?name=${RECORD_NAME}&type=A" \
 76→            -H "X-Auth-Email: ${CLOUDFLARE_EMAIL}" \
 77→            -H "X-Auth-Key: ${CLOUDFLARE_API_KEY}" \
 78→            -H "Content-Type: application/json")
 79→
 80→        COUNT=$(echo "$EXISTING" | python3 -c "import sys,json; print(len(json.load(sys.stdin)['result']))" 2>/dev/null || echo "0")
 81→
 82→        if [ "$COUNT" -gt "0" ]; then
 83→            RECORD_ID=$(echo "$EXISTING" | python3 -c "import sys,json; print(json.load(sys.stdin)['result'][0]['id'])")
 84→            info "Updating existing record for ${RECORD_NAME}..."
 85→            RESULT=$(curl -s -X PUT \
 86→                "https://api.cloudflare.com/client/v4/zones/${CF_ZONE_TASKAI}/dns_records/${RECORD_ID}" \
 87→                -H "X-Auth-Email: ${CLOUDFLARE_EMAIL}" \
 88→                -H "X-Auth-Key: ${CLOUDFLARE_API_KEY}" \
 89→                -H "Content-Type: application/json" \
 90→                --data "{\"type\":\"A\",\"name\":\"${RECORD_NAME}\",\"content\":\"${SERVER_IP}\",\"ttl\":1,\"proxied\":false}")
 91→        else
 92→            info "Creating A record for ${RECORD_NAME} → ${SERVER_IP}..."
 93→            RESULT=$(curl -s -X POST \
 94→                "https://api.cloudflare.com/client/v4/zones/${CF_ZONE_TASKAI}/dns_records" \
 95→                -H "X-Auth-Email: ${CLOUDFLARE_EMAIL}" \
 96→                -H "X-Auth-Key: ${CLOUDFLARE_API_KEY}" \
 97→                -H "Content-Type: application/json" \
 98→                --data "{\"type\":\"A\",\"name\":\"${RECORD_NAME}\",\"content\":\"${SERVER_IP}\",\"ttl\":1,\"proxied\":false}")
 99→        fi
100→
101→        SUCCESS=$(echo "$RESULT" | python3 -c "import sys,json; print(json.load(sys.stdin)['success'])" 2>/dev/null || echo "False")
102→        if [ "$SUCCESS" = "True" ]; then
103→            ok "DNS: ${RECORD_NAME} → ${SERVER_IP}"
104→        else
105→            fail "DNS failed for ${RECORD_NAME}: $(echo "$RESULT" | python3 -c "import sys,json; print(json.load(sys.stdin).get('errors','unknown'))" 2>/dev/null)"
106→            exit 1
107→        fi
108→    done
109→}
110→
111→# Step 2: Rename server directories and DB files
112→rename_server_dirs() {
113→    step 2 "Renaming server directories and DB files"
114→
115→    $SSH << 'REMOTE_SCRIPT'
116→set -e
117→
118→echo "-> Checking current state..."
119→
120→# Check what exists
121→OLD_STAGING="/home/ubuntu/sprintspark-staging"
122→NEW_STAGING="/home/ubuntu/taskai-staging"
123→OLD_PROD="/home/ubuntu/sprintspark"
124→NEW_PROD="/home/ubuntu/taskai"
125→
126→# --- Staging ---
127→if [ -d "$OLD_STAGING" ]; then
128→    echo "-> Stopping staging containers..."
129→    cd "$OLD_STAGING" && docker compose down 2>/dev/null || true
130→    cd /home/ubuntu
131→
132→    echo "-> Renaming staging directory..."
133→    mv "$OLD_STAGING" "$NEW_STAGING"
134→    echo "OK: $OLD_STAGING → $NEW_STAGING"
135→elif [ -d "$NEW_STAGING" ]; then
136→    echo "SKIP: $NEW_STAGING already exists"
137→else
138→    echo "WARN: Neither $OLD_STAGING nor $NEW_STAGING exists"
139→fi
140→
141→# --- Production ---
142→if [ -d "$OLD_PROD" ]; then
143→    echo "-> Stopping production containers..."
144→    cd "$OLD_PROD" && docker compose down 2>/dev/null || true
145→    cd /home/ubuntu
146→
147→    echo "-> Renaming production directory..."
148→    mv "$OLD_PROD" "$NEW_PROD"
149→    echo "OK: $OLD_PROD → $NEW_PROD"
150→elif [ -d "$NEW_PROD" ]; then
151→    echo "SKIP: $NEW_PROD already exists"
152→else
153→    echo "WARN: Neither $OLD_PROD nor $NEW_PROD exists"
154→fi
155→
156→# --- Rename DB files inside data directories ---
157→for DIR in "$NEW_STAGING" "$NEW_PROD"; do
158→    if [ -d "$DIR/data" ]; then
159→        if [ -f "$DIR/data/sprintspark.db" ]; then
160→            echo "-> Renaming DB in $DIR/data..."
161→            mv "$DIR/data/sprintspark.db" "$DIR/data/taskai.db"
162→            [ -f "$DIR/data/sprintspark.db-shm" ] && mv "$DIR/data/sprintspark.db-shm" "$DIR/data/taskai.db-shm"
163→            [ -f "$DIR/data/sprintspark.db-wal" ] && mv "$DIR/data/sprintspark.db-wal" "$DIR/data/taskai.db-wal"
164→            echo "OK: DB renamed in $DIR"
165→        elif [ -f "$DIR/data/taskai.db" ]; then
166→            echo "SKIP: $DIR/data/taskai.db already exists"
167→        fi
168→    fi
169→done
170→
171→# --- Also check Docker volumes for DB files ---
172→echo "-> Checking Docker volumes..."
173→for VOL in sprintspark-staging-data sprintspark-data; do
174→    MOUNT=$(docker volume inspect "$VOL" --format '{{ .Mountpoint }}' 2>/dev/null || echo "")
175→    if [ -n "$MOUNT" ] && [ -f "$MOUNT/sprintspark.db" ]; then
176→        echo "-> Renaming DB in Docker volume $VOL..."
177→        sudo mv "$MOUNT/sprintspark.db" "$MOUNT/taskai.db"
178→        [ -f "$MOUNT/sprintspark.db-shm" ] && sudo mv "$MOUNT/sprintspark.db-shm" "$MOUNT/taskai.db-shm"
179→        [ -f "$MOUNT/sprintspark.db-wal" ] && sudo mv "$MOUNT/sprintspark.db-wal" "$MOUNT/taskai.db-wal"
180→        echo "OK: DB renamed in volume $VOL"
181→    fi
182→done
183→
184→echo "-> Directory and DB renames complete"
185→REMOTE_SCRIPT
186→
187→    ok "Server directories and DB files renamed"
188→}
189→
190→# Step 3: Update webhook config on server
191→update_webhook_config() {
192→    step 3 "Updating webhook config on server"
193→
194→    # Read the local webhook config and push it to the server
195→    info "Copying webhook config to server..."
196→    scp "$(dirname "$0")/../webhook/config.yaml" "${REMOTE_USER}@${REMOTE_HOST}:/home/ubuntu/webhooks/config.yaml"
197→
198→    # Restart the webhook service
199→    $SSH << 'REMOTE_SCRIPT'
200→echo "-> Restarting webhook service..."
201→cd /home/ubuntu/webhooks
202→if [ -f docker-compose.yml ]; then
203→    docker compose restart 2>/dev/null || docker compose up -d 2>/dev/null || true
204→elif systemctl is-active --quiet webhook 2>/dev/null; then
205→    sudo systemctl restart webhook
206→fi
207→echo "OK: Webhook config updated"
208→REMOTE_SCRIPT
209→
210→    ok "Webhook config updated on server"
211→}
212→
213→# Step 4: Nginx configs for new domains
214→setup_nginx() {
215→    step 4 "Setting up Nginx for new domains"
216→
217→    $SSH << 'REMOTE_SCRIPT'
218→set -e
219→
220→# staging.taskai.cc - pre-SSL config
221→if [ ! -f "/etc/nginx/sites-available/staging.taskai.cc" ]; then
222→    echo "-> Creating Nginx config for staging.taskai.cc..."
223→    sudo tee /etc/nginx/sites-available/staging.taskai.cc > /dev/null << 'NGINX_CONF'
224→server {
225→    listen 80;
226→    listen [::]:80;
227→    server_name staging.taskai.cc;
228→
229→    location /.well-known/acme-challenge/ {
230→        root /var/www/html;
231→    }
232→
233→    location / {
234→        return 200 'Server is ready for SSL setup';
235→        add_header Content-Type text/plain;
236→    }
237→}
238→NGINX_CONF
239→    sudo ln -sf /etc/nginx/sites-available/staging.taskai.cc /etc/nginx/sites-enabled/
240→    echo "OK: staging.taskai.cc nginx config created"
241→else
242→    echo "SKIP: staging.taskai.cc nginx config already exists"
243→fi
244→
245→# mcp.staging.taskai.cc - pre-SSL config
246→if [ ! -f "/etc/nginx/sites-available/mcp.staging.taskai.cc" ]; then
247→    echo "-> Creating Nginx config for mcp.staging.taskai.cc..."
248→    sudo tee /etc/nginx/sites-available/mcp.staging.taskai.cc > /dev/null << 'NGINX_CONF'
249→server {
250→    listen 80;
251→    listen [::]:80;
252→    server_name mcp.staging.taskai.cc;
253→
254→    location /.well-known/acme-challenge/ {
255→        root /var/www/html;
256→    }
257→
258→    location / {
259→        return 200 'Server is ready for SSL setup';
260→        add_header Content-Type text/plain;
261→    }
262→}
263→NGINX_CONF
264→    sudo ln -sf /etc/nginx/sites-available/mcp.staging.taskai.cc /etc/nginx/sites-enabled/
265→    echo "OK: mcp.staging.taskai.cc nginx config created"
266→else
267→    echo "SKIP: mcp.staging.taskai.cc nginx config already exists"
268→fi
269→
270→# Remove old sprintspark nginx configs
271→for OLD_CONF in sprintspark.biswas.me mcp.sprintspark.biswas.me; do
272→    if [ -f "/etc/nginx/sites-enabled/$OLD_CONF" ]; then
273→        echo "-> Removing old nginx config for $OLD_CONF..."
274→        sudo rm -f "/etc/nginx/sites-enabled/$OLD_CONF"
275→    fi
276→done
277→
278→sudo nginx -t && sudo systemctl reload nginx
279→echo "OK: Nginx reloaded"
280→REMOTE_SCRIPT
281→
282→    ok "Nginx configs created for new domains"
283→}
284→
285→# Step 5: SSL certificates
286→setup_ssl() {
287→    step 5 "Setting up SSL certificates"
288→
289→    info "Waiting 30s for DNS propagation..."
290→    sleep 30
291→
292→    $SSH << 'REMOTE_SCRIPT'
293→set -e
294→
295→for DOMAIN in staging.taskai.cc mcp.staging.taskai.cc; do
296→    if [ -f "/etc/letsencrypt/live/$DOMAIN/fullchain.pem" ]; then
297→        echo "SKIP: SSL cert already exists for $DOMAIN"
298→    else
299→        echo "-> Obtaining SSL cert for $DOMAIN..."
300→        sudo certbot --nginx -d "$DOMAIN" \
301→            --non-interactive --agree-tos \
302→            --email anshuman@biswas.me \
303→            --redirect
304→        echo "OK: SSL cert obtained for $DOMAIN"
305→    fi
306→done
307→REMOTE_SCRIPT
308→
309→    ok "SSL certificates configured"
310→}
311→
312→# Step 6: Create full Nginx SSL configs and restart apps
313→finalize_nginx() {
314→    step 6 "Creating full Nginx SSL configs"
315→
316→    $SSH << 'REMOTE_SCRIPT'
317→set -e
318→
319→# staging.taskai.cc - full SSL config
320→if [ -f "/etc/letsencrypt/live/staging.taskai.cc/fullchain.pem" ]; then
321→    echo "-> Writing full SSL Nginx config for staging.taskai.cc..."
322→    sudo tee /etc/nginx/sites-available/staging.taskai.cc > /dev/null << 'NGINX_CONF'
323→# Nginx configuration for staging.taskai.cc (with SSL)
324→
325→limit_req_zone $binary_remote_addr zone=staging_taskai_cc_api:10m rate=100r/m;
326→limit_req_zone $binary_remote_addr zone=staging_taskai_cc_auth:10m rate=20r/m;
327→
328→server {
329→    listen 80;
330→    listen [::]:80;
331→    server_name staging.taskai.cc;
332→
333→    location /.well-known/acme-challenge/ {
334→        root /var/www/html;
335→    }
336→
337→    location / {
338→        return 301 https://$server_name$request_uri;
339→    }
340→}
341→
342→server {
343→    listen 443 ssl;
344→    listen [::]:443 ssl;
345→    http2 on;
346→    server_name staging.taskai.cc;
347→
348→    ssl_certificate /etc/letsencrypt/live/staging.taskai.cc/fullchain.pem;
349→    ssl_certificate_key /etc/letsencrypt/live/staging.taskai.cc/privkey.pem;
350→    ssl_session_timeout 1d;
351→    ssl_session_cache shared:SSL:50m;
352→    ssl_session_tickets off;
353→
354→    ssl_protocols TLSv1.2 TLSv1.3;
355→    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
356→    ssl_prefer_server_ciphers off;
357→
358→    ssl_stapling on;
359→    ssl_stapling_verify on;
360→    ssl_trusted_certificate /etc/letsencrypt/live/staging.taskai.cc/chain.pem;
361→
362→    add_header Strict-Transport-Security "max-age=63072000" always;
363→    add_header X-Frame-Options "SAMEORIGIN" always;
364→    add_header X-Content-Type-Options "nosniff" always;
365→    add_header X-XSS-Protection "1; mode=block" always;
366→    add_header Referrer-Policy "no-referrer-when-downgrade" always;
367→
368→    access_log /var/log/nginx/staging.taskai.cc_access.log;
369→    error_log /var/log/nginx/staging.taskai.cc_error.log;
370→
371→    client_max_body_size 10M;
372→
373→    location ~ ^/api/auth {
374→        limit_req zone=staging_taskai_cc_auth burst=3 nodelay;
375→        proxy_pass http://127.0.0.1:8082;
376→        proxy_http_version 1.1;
377→        proxy_set_header Host $host;
378→        proxy_set_header X-Real-IP $remote_addr;
379→        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
380→        proxy_set_header X-Forwarded-Proto $scheme;
381→    }
382→
383→    location /api/ {
384→        limit_req zone=staging_taskai_cc_api burst=20 nodelay;
385→        proxy_pass http://127.0.0.1:8082;
386→        proxy_http_version 1.1;
387→        proxy_set_header Upgrade $http_upgrade;
388→        proxy_set_header Connection 'upgrade';
389→        proxy_set_header Host $host;
390→        proxy_set_header X-Real-IP $remote_addr;
391→        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
392→        proxy_set_header X-Forwarded-Proto $scheme;
393→        proxy_cache_bypass $http_upgrade;
394→        proxy_connect_timeout 60s;
395→        proxy_send_timeout 60s;
396→        proxy_read_timeout 60s;
397→    }
398→
399→    location /health {
400→        proxy_pass http://127.0.0.1:8082;
401→        access_log off;
402→    }
403→
404→    location / {
405→        proxy_pass http://127.0.0.1:8086;
406→        proxy_http_version 1.1;
407→        proxy_set_header Upgrade $http_upgrade;
408→        proxy_set_header Connection 'upgrade';
409→        proxy_set_header Host $host;
410→        proxy_set_header X-Real-IP $remote_addr;
411→        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
412→        proxy_set_header X-Forwarded-Proto $scheme;
413→        proxy_cache_bypass $http_upgrade;
414→
415→        location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot)$ {
416→            proxy_pass http://127.0.0.1:8086;
417→            expires 1y;
418→            add_header Cache-Control "public, immutable";
419→        }
420→    }
421→
422→    gzip on;
423→    gzip_vary on;
424→    gzip_proxied any;
425→    gzip_comp_level 6;
426→    gzip_types text/plain text/css text/xml text/javascript application/json application/javascript application/xml+rss application/rss+xml font/truetype font/opentype application/vnd.ms-fontobject image/svg+xml;
427→}
428→NGINX_CONF
429→    echo "OK: staging.taskai.cc full SSL config"
430→fi
431→
432→# mcp.staging.taskai.cc - full SSL config
433→if [ -f "/etc/letsencrypt/live/mcp.staging.taskai.cc/fullchain.pem" ]; then
434→    echo "-> Writing full SSL Nginx config for mcp.staging.taskai.cc..."
435→    sudo tee /etc/nginx/sites-available/mcp.staging.taskai.cc > /dev/null << 'NGINX_CONF'
436→# Nginx configuration for mcp.staging.taskai.cc (with SSL)
437→
438→server {
439→    listen 80;
440→    listen [::]:80;
441→    server_name mcp.staging.taskai.cc;
442→
443→    location /.well-known/acme-challenge/ {
444→        root /var/www/html;
445→    }
446→
447→    location / {
448→        return 301 https://$server_name$request_uri;
449→    }
450→}
451→
452→server {
453→    listen 443 ssl;
454→    listen [::]:443 ssl;
455→    http2 on;
456→    server_name mcp.staging.taskai.cc;
457→
458→    ssl_certificate /etc/letsencrypt/live/mcp.staging.taskai.cc/fullchain.pem;
459→    ssl_certificate_key /etc/letsencrypt/live/mcp.staging.taskai.cc/privkey.pem;
460→    ssl_session_timeout 1d;
461→    ssl_session_cache shared:SSL:50m;
462→    ssl_session_tickets off;
463→
464→    ssl_protocols TLSv1.2 TLSv1.3;
465→    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
466→    ssl_prefer_server_ciphers off;
467→
468→    ssl_stapling on;
469→    ssl_stapling_verify on;
470→    ssl_trusted_certificate /etc/letsencrypt/live/mcp.staging.taskai.cc/chain.pem;
471→
472→    add_header Strict-Transport-Security "max-age=63072000" always;
473→    add_header X-Frame-Options "SAMEORIGIN" always;
474→    add_header X-Content-Type-Options "nosniff" always;
475→
476→    access_log /var/log/nginx/mcp.staging.taskai.cc_access.log;
477→    error_log /var/log/nginx/mcp.staging.taskai.cc_error.log;
478→
479→    client_max_body_size 1M;
480→
481→    location /health {
482→        proxy_pass http://127.0.0.1:8084;
483→        access_log off;
484→    }
485→
486→    location /mcp {
487→        proxy_pass http://127.0.0.1:8084;
488→        proxy_http_version 1.1;
489→        proxy_set_header Host $host;
490→        proxy_set_header X-Real-IP $remote_addr;
491→        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
492→        proxy_set_header X-Forwarded-Proto $scheme;
493→        proxy_connect_timeout 60s;
494→        proxy_send_timeout 60s;
495→        proxy_read_timeout 60s;
496→    }
497→
498→    location / {
499→        return 404;
500→    }
501→
502→    gzip on;
503→    gzip_vary on;
504→    gzip_proxied any;
505→    gzip_comp_level 6;
506→    gzip_types application/json;
507→}
508→NGINX_CONF
509→    echo "OK: mcp.staging.taskai.cc full SSL config"
510→fi
511→
512→sudo nginx -t && sudo systemctl reload nginx
513→echo "OK: Nginx reloaded with SSL configs"
514→REMOTE_SCRIPT
515→
516→    ok "Full Nginx SSL configs deployed"
517→}
518→
519→# Step 7: Update docker-compose on server and restart apps
520→restart_apps() {
521→    step 7 "Restarting applications"
522→
523→    $SSH << 'REMOTE_SCRIPT'
524→set -e
525→
526→# Update git remote in both environments
527→for DIR in /home/ubuntu/taskai-staging/source /home/ubuntu/taskai/source; do
528→    if [ -d "$DIR/.git" ]; then
529→        echo "-> Updating git remote in $DIR..."
530→        cd "$DIR"
531→        git remote set-url origin https://github.com/anchoo2kewl/taskai.git
532→        git pull origin main
533→        echo "OK: Git updated in $DIR"
534→    fi
535→done
536→
537→# Rebuild and start staging
538→if [ -d "/home/ubuntu/taskai-staging" ]; then
539→    echo "-> Rebuilding staging..."
540→    cd /home/ubuntu/taskai-staging
541→    docker compose build --no-cache
542→    docker compose up -d
543→    sleep 10
544→    echo "OK: Staging started"
545→fi
546→
547→# Rebuild and start production
548→if [ -d "/home/ubuntu/taskai" ]; then
549→    echo "-> Rebuilding production..."
550→    cd /home/ubuntu/taskai
551→    docker compose build --no-cache
552→    docker compose up -d
553→    sleep 10
554→    echo "OK: Production started"
555→fi
556→REMOTE_SCRIPT
557→
558→    ok "Applications restarted"
559→}
560→
561→# Step 8: GitHub secrets
562→setup_github_secrets() {
