# Nginx configuration for taskai.cc (with SSL)

# Rate limiting zones
limit_req_zone $binary_remote_addr zone=taskai_cc_api:10m rate=100r/m;
limit_req_zone $binary_remote_addr zone=taskai_cc_auth:10m rate=20r/m;

# HTTP -> HTTPS redirect
server {
    listen 80;
    listen [::]:80;
    server_name taskai.cc;

    # Let's Encrypt verification
    location /.well-known/acme-challenge/ {
        root /var/www/html;
    }

    # Redirect all other traffic to HTTPS
    location / {
        return 301 https://$server_name$request_uri;
    }
}

# HTTPS server
server {
    listen 443 ssl;
    listen [::]:443 ssl;
    http2 on;
    server_name taskai.cc;

    # SSL configuration
    ssl_certificate /etc/letsencrypt/live/taskai.cc/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/taskai.cc/privkey.pem;
    ssl_session_timeout 1d;
    ssl_session_cache shared:SSL:50m;
    ssl_session_tickets off;

    # Modern SSL configuration
    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
    ssl_prefer_server_ciphers off;

    # OCSP stapling
    ssl_stapling on;
    ssl_stapling_verify on;
    ssl_trusted_certificate /etc/letsencrypt/live/taskai.cc/chain.pem;

